133	impl syn::parse::Parse for Argument {
134	    fn parse(input: syn::parse::ParseStream) -> syn::parse::Result<Self> {
135	        // Ignore leading commas.
136	        while input.peek(Token![,]) {
137	            let _ = input.parse::<Token![,]>()?;
138	        }
139	        // Parse the argument name.
140	        let name = Self::try_ident(input)
141	            .or_else(|_| Self::try_literal(input))
142	            .map_err(|_| input.error("Expected a `string` literal or an identifier"))?;
143	        // Parse the separator between the name and the value.
144	        if input.peek(Token![=>]) {
145	            let _ = input.parse::<Token![=>]>()?;
146	        } else if input.peek(Token![=]) {
147	            let _ = input.parse::<Token![=]>()?;
148	        } else {
149	            return Err(input.error("Expected `=>` or `=`"));
150	        }
151	        // Parse the argument value.
152	        let value = input.parse()?;
153	        // Parse the specifiers [optinal].
154	        let specifiers = if input.peek(Token![:]) {
155	            let _ = input.parse::<Token![:]>()?;
156	            if input.peek(Brace) {
157	                let content;
158	                let _ = syn::braced!(content in input);
159	                let mut specifiers = String::new();
160	                while let Ok(s) = content.parse::<proc_macro2::TokenTree>() {
161	                    specifiers.push_str(&s.to_string());
162	                }
163	                Some(specifiers)
164	            } else {
165	                None
166	            }
167	        } else {
168	            None
169	        };
170	        Ok(Self {
171	            name,
172	            value,
173	            specifiers,
174	        })
175	    }
176	}
